const ticker = ($input.first().json.query?.ticker || $input.first().json.body?.ticker || '').toString().trim().toUpperCase();

if (!ticker || ticker.length === 0) {
  throw new Error('Missing ticker parameter. Use: ?ticker=AAPL');
}
if (!/^[A-Z.\-]{1,10}$/.test(ticker)) {
  throw new Error(`Invalid ticker symbol: "${ticker}". Use standard stock symbols like AAPL, MSFT, GOOGL.`);
}

return [{ json: { ticker } }];

const ticker = $('Validate Ticker').first().json.ticker;
const n = (v) => (v !== null && v !== undefined && v !== '' && !isNaN(Number(v))) ? Number(v) : 0;

// ── FMP Quote (market data) ────────────────────────────────────────────
const quoteRaw = $('FMP — Quote').first().json;
let q;
if (Array.isArray(quoteRaw) && quoteRaw.length > 0) { q = quoteRaw[0]; }
else if (quoteRaw && typeof quoteRaw === 'object' && (quoteRaw.price || quoteRaw.symbol)) { q = quoteRaw; }
else { throw new Error(`FMP quote failed for "${ticker}": ${JSON.stringify(quoteRaw).slice(0, 200)}`); }

const currentPrice      = n(q.price);
const marketCap         = n(q.marketCap);
const sharesOutstanding = n(q.sharesOutstanding) || (marketCap > 0 && currentPrice > 0 ? marketCap / currentPrice : 0);
const beta              = 1.0; // FMP free tier omits beta; market-neutral default
const companyName       = q.name || ticker;
const exchange          = q.exchange || 'N/A';

if (currentPrice === 0) throw new Error(`FMP quote returned zero price for "${ticker}". Check ticker is valid.`);

// ── SEC EDGAR Company Facts (XBRL, 100% free) ─────────────────────────
const secData = $('SEC — Company Facts').first().json;
if (!secData || !secData.facts) {
  throw new Error(`SEC EDGAR returned no company facts for "${ticker}". Ensure ticker is a US-listed company with SEC filings.`);
}
const facts = secData.facts;
const edgarName = secData.entityName || companyName;

// Helper: get annual 10-K FY values for XBRL concept list (newest first)
function getAnnual(concepts, maxYears) {
  if (!maxYears) maxYears = 5;
  for (const concept of concepts) {
    const usgaap = facts['us-gaap'];
    if (!usgaap || !usgaap[concept]) continue;
    const usdUnits = usgaap[concept].units;
    if (!usdUnits || !usdUnits.USD) continue;
    const usd = usdUnits.USD;
    if (!Array.isArray(usd) || usd.length === 0) continue;
    const annual = usd
      .filter(d => d.form === '10-K' && d.fp === 'FY')
      .sort((a, b) => new Date(b.end) - new Date(a.end));
    if (annual.length > 0) return annual.slice(0, maxYears);
  }
  return [];
}

// ── Revenue (3 years for 2-yr CAGR) ──────────────────────────────────────
const revRows = getAnnual([
  'RevenueFromContractWithCustomerExcludingAssessedTax',
  'Revenues', 'SalesRevenueNet',
  'RevenueFromContractWithCustomerIncludingAssessedTax',
  'SalesRevenueGoodsNet', 'RevenueFromContractWithCustomer',
], 3);
const revenue      = n(revRows[0]?.val);
const revenue_prev = n(revRows[1]?.val);
const revenue_p2   = n(revRows[2]?.val);
if (revenue === 0) throw new Error(`SEC EDGAR: no revenue data found for "${ticker}". This ticker may not file 10-Ks with the SEC.`);

// ── Operating Income (EBIT proxy) ──────────────────────────────────────────
const ebitRows = getAnnual(['OperatingIncomeLoss'], 1);
const ebit = n(ebitRows[0]?.val);

// ── Net Income ────────────────────────────────────────────────────────────
const niRows = getAnnual(['NetIncomeLoss','ProfitLoss','NetIncomeLossAvailableToCommonStockholdersBasic'], 1);
const netIncome = n(niRows[0]?.val);

// ── Interest Expense ──────────────────────────────────────────────────────
const intRows = getAnnual(['InterestExpense','InterestExpenseDebt','InterestAndDebtExpense'], 1);
const interestExpense = Math.abs(n(intRows[0]?.val));

// ── Income Tax ────────────────────────────────────────────────────────────
const taxRows = getAnnual(['IncomeTaxExpenseBenefit'], 1);
const incomeTax = n(taxRows[0]?.val);

const ptRows = getAnnual([
  'IncomeLossFromContinuingOperationsBeforeIncomeTaxesExtraordinaryItemsNoncontrollingInterest',
  'IncomeLossFromContinuingOperationsBeforeIncomeTaxesMinorityInterestAndIncomeLossFromEquityMethodInvestments',
], 1);
const preTaxIncome = ptRows.length > 0 ? n(ptRows[0]?.val) : (netIncome + incomeTax);
const taxRate = preTaxIncome > 0 ? Math.max(0.05, Math.min(0.40, incomeTax / preTaxIncome)) : 0.21;

// ── Debt ──────────────────────────────────────────────────────────────────
const ltdRows = getAnnual(['LongTermDebt','LongTermDebtNoncurrent','LongTermDebtAndCapitalLeaseObligations'], 1);
const longTermDebt = n(ltdRows[0]?.val);
const stdRows = getAnnual(['ShortTermBorrowings','DebtCurrent','LongTermDebtCurrent','LongTermDebtCurrentMaturities'], 1);
const shortTermDebt = n(stdRows[0]?.val);
const totalDebt = longTermDebt + shortTermDebt;

// ── Cash ──────────────────────────────────────────────────────────────────
const cashRows = getAnnual([
  'CashAndCashEquivalentsAtCarryingValue','Cash','CashAndCashEquivalents',
  'CashCashEquivalentsAndShortTermInvestments',
], 1);
const cash = n(cashRows[0]?.val);

// ── Equity ────────────────────────────────────────────────────────────────
const eqRows = getAnnual(['StockholdersEquity','StockholdersEquityIncludingPortionAttributableToNoncontrollingInterest'], 1);
const totalEquity = n(eqRows[0]?.val);

// ── Cash Flow ─────────────────────────────────────────────────────────────
const ocfRows = getAnnual(['NetCashProvidedByUsedInOperatingActivities'], 1);
const operatingCashFlow = n(ocfRows[0]?.val);

const cxRows = getAnnual(['PaymentsToAcquirePropertyPlantAndEquipment','PaymentsToAcquireProductiveAssets'], 1);
const capex = Math.abs(n(cxRows[0]?.val));

const dnaRows = getAnnual(['DepreciationDepletionAndAmortization','Depreciation','DepreciationAndAmortization'], 1);
const depreciationAmortization = n(dnaRows[0]?.val);

// ── Derived metrics ───────────────────────────────────────────────────────
// Revenue 2-yr CAGR capped at ±20% (standard DCF practice)
let revenueGrowth = 0.07;
if (revenue > 0 && revenue_p2 > 0) {
  revenueGrowth = Math.pow(revenue / revenue_p2, 0.5) - 1;
} else if (revenue > 0 && revenue_prev > 0) {
  revenueGrowth = (revenue / revenue_prev) - 1;
}
revenueGrowth = Math.max(-0.50, Math.min(0.20, revenueGrowth));

const ebitMargin = revenue > 0 ? ebit / revenue : 0;

// Reinvestment Rate (FCFF method)
// RR = (CapEx − D&A) / NOPAT  → bounded [0, 1]
const nopat = ebit * (1 - taxRate);
const netCapex = capex - depreciationAmortization;
const reinvestmentRate = nopat > 0 ? Math.max(0, Math.min(0.95, netCapex / nopat)) : 0.30;

// Free Cash Flow
const fcf = operatingCashFlow - capex;
const fcfMargin = revenue > 0 ? fcf / revenue : 0;

// Cost of debt
const costOfDebt = (totalDebt > 0 && interestExpense > 0)
  ? Math.max(0.02, Math.min(0.15, interestExpense / totalDebt))
  : 0.04; // synthetic spread fallback

// Valuation ratios (for HTML report)
const enterpriseValueMkt = marketCap + totalDebt - cash;
const ebitda = ebit + depreciationAmortization;
const evToEbitda = ebitda > 0 ? enterpriseValueMkt / ebitda : 0;
const debtToEquity = totalEquity !== 0 ? totalDebt / Math.abs(totalEquity) : 0;
const roic = (totalDebt + Math.abs(totalEquity)) > 0 ? nopat / (totalDebt + Math.abs(totalEquity)) : 0;
const epsTrailing = sharesOutstanding > 0 ? netIncome / sharesOutstanding : 0;
const trailingPE = epsTrailing > 0 ? currentPrice / epsTrailing : 0;

// SEC EDGAR metadata
const cikSrc = $('SEC EDGAR — CIK Lookup').first().json?.hits?.hits?.[0]?._source || {};
const secCIK = (cikSrc.entity_id || (Array.isArray(cikSrc.ciks) ? cikSrc.ciks[0] : cikSrc.ciks) || '').toString().replace(/^CIK/i, '');
const secFilingUrl = secCIK
  ? `https://www.sec.gov/cgi-bin/browse-edgar?action=getcompany&CIK=${secCIK}&type=10-K&dateb=&owner=include&count=5`
  : 'https://www.sec.gov/cgi-bin/browse-edgar';
const valuationDate = new Date().toISOString().slice(0, 10);

return [{
  json: {
    // Identifiers
    ticker, companyName: edgarName, exchange,
    sector: 'N/A', industry: 'N/A', currency: 'USD', valuationDate,
    // Market data (FMP)
    currentPrice, marketCap, sharesOutstanding, beta,
    // Income (SEC EDGAR)
    revenue, revenue_prev, revenue_p2, revenueGrowth,
    ebit, ebitMargin, netIncome, interestExpense, incomeTax, taxRate,
    // Balance sheet (SEC EDGAR)
    totalDebt, cash, totalEquity,
    // Cash flow (SEC EDGAR)
    operatingCashFlow, capex, depreciationAmortization, fcf, fcfMargin,
    // DCF inputs
    nopat, reinvestmentRate, costOfDebt,
    // Ratios (HTML report)
    enterpriseValueMkt, evToEbitda, debtToEquity, roic,
    trailingPE, forwardPE: 0,
    // SEC metadata
    secCIK, secFilingUrl,
    // Debug
    _dataSource: 'SEC EDGAR XBRL (financials) + FMP /stable/quote (market data)',
    _betaNote: 'Defaulted to 1.0 — not available on FMP free tier'
  }
}];

// Extract the 10-year US Treasury yield from Yahoo Finance ^TNX
// ^TNX is quoted in percent (e.g., 4.25 = 4.25%)

const tnxData = $('Yahoo Finance — Risk-Free Rate').first().json;
let riskFreeRate = 0.042; // fallback: 4.2%

try {
  const closes = tnxData?.chart?.result?.[0]?.indicators?.quote?.[0]?.close;
  if (closes && Array.isArray(closes)) {
    const validCloses = closes.filter(v => v !== null && v !== undefined && !isNaN(v));
    if (validCloses.length > 0) {
      const latest = validCloses[validCloses.length - 1];
      riskFreeRate = latest / 100;
    }
  }
} catch (e) {
  // Use fallback silently
}

// Published Implied Equity Risk Premium
// Source: https://pages.stern.nyu.edu (NYU Stern)
// Updated annually in January. Using Jan 2025 value: 4.60%
const equityRiskPremium = 0.046;

return [{ json: { riskFreeRate, equityRiskPremium } }];

// ============================================================
// STEP 2: WACC CALCULATION (Standard DCF Methodology)
// ============================================================
// WACC = We × Re + Wd × Rd(1−t)
// Re  = Rf + β × ERP  (CAPM)
// Rd  = Interest Expense / Total Debt
// We  = Market Cap / (Market Cap + Total Debt)
// Wd  = Total Debt / (Market Cap + Total Debt)

const fin = $('Extract Financial Data').first().json;
const rates = $('Parse Risk-Free Rate').first().json;

const riskFreeRate = rates.riskFreeRate;
const ERP = rates.equityRiskPremium;

// --- COST OF EQUITY (CAPM) ---
const beta = fin.beta || 1.0;
const costOfEquity = riskFreeRate + (beta * ERP);

// --- COST OF DEBT ---
let costOfDebtPretax;
if (fin.totalDebt > 0 && fin.interestExpense > 0) {
  costOfDebtPretax = fin.interestExpense / fin.totalDebt;
  // Bound to reasonable range: synthetic rating approach
  // (avoids distortion from short-term debt fluctuations)
  costOfDebtPretax = Math.max(0.015, Math.min(costOfDebtPretax, 0.15));
} else {
  // Default: use risk-free rate + default spread for investment-grade firm
  costOfDebtPretax = riskFreeRate + 0.015; // ~1.5% default spread
}
const afterTaxCostOfDebt = costOfDebtPretax * (1 - fin.taxRate);

// --- CAPITAL STRUCTURE WEIGHTS (Market Value) ---
const marketCap = fin.marketCap;
const totalDebt = fin.totalDebt;
const totalCapital = marketCap + totalDebt;
const weightEquity = totalCapital > 0 ? marketCap / totalCapital : 0.85;
const weightDebt = totalCapital > 0 ? totalDebt / totalCapital : 0.15;

// --- WACC ---
const wacc = (weightEquity * costOfEquity) + (weightDebt * afterTaxCostOfDebt);

// Sanity check: WACC must be > terminal growth rate (2.5%)
if (wacc <= 0.025) {
  throw new Error(`WACC (${(wacc*100).toFixed(2)}%) is too low for a valid DCF. Check beta and debt data.`);
}

return [{
  json: {
    riskFreeRate,
    ERP,
    beta,
    costOfEquity,
    costOfDebtPretax,
    afterTaxCostOfDebt,
    weightEquity,
    weightDebt,
    wacc,
    // WACC component breakdown (for report)
    waccComponents: {
      equityContribution: weightEquity * costOfEquity,
      debtContribution: weightDebt * afterTaxCostOfDebt,
    }
  }
}];

// ============================================================
// STEP 3: 10-YEAR DCF VALUATION (Standard DCF Framework)
// ============================================================

const fin = $('Extract Financial Data').first().json;
const waccData = $('Calculate WACC').first().json;

const wacc = waccData.wacc;
const taxRate = fin.taxRate;

// ---- GROWTH RATE ASSUMPTIONS ----
// Standard DCF framework: 3 stages of growth
//   Stage 1 (Yr 1-5): Aggressive growth anchored to historical CAGR
//   Stage 2 (Yr 6-10): Transition phase tapering toward stable growth
//   Terminal: Perpetuity growth ≤ nominal GDP growth (2.5%)

const historicalRevGrowth = fin.revenueGrowth;
// Cap Stage 1 at 20% (practical upper bound for mature markets)
const stage1Growth = Math.min(Math.max(historicalRevGrowth, 0), 0.20);
const terminalGrowthRate = 0.025; // 2.5% perpetuity
const stage2Growth = (stage1Growth + terminalGrowthRate) / 2; // Linear taper

// ---- FCF PROJECTION USING NOPAT METHOD ----
// FCF = NOPAT × (1 − Reinvestment Rate)
// This follows the FCFF approach

const baseRevenue = fin.revenue;
const ebitMargin = fin.ebitMargin;
const reinvestmentRate = fin.reinvestmentRate;

const projectedYears = [];
let runningRevenue = baseRevenue;

for (let year = 1; year <= 10; year++) {
  const growthRate = year <= 5 ? stage1Growth : stage2Growth;
  runningRevenue = runningRevenue * (1 + growthRate);

  // EBIT (assuming stable margin; can be refined with sector data)
  const ebitProjected = runningRevenue * ebitMargin;

  // NOPAT
  const nopatProjected = ebitProjected * (1 - taxRate);

  // FCF to Firm (FCFF) = NOPAT × (1 − Reinvestment Rate)
  const fcfProjected = nopatProjected * (1 - reinvestmentRate);

  // Present Value
  const pvFactor = Math.pow(1 + wacc, year);
  const pv = fcfProjected / pvFactor;

  projectedYears.push({
    year,
    growthRate,
    revenue: runningRevenue,
    ebit: ebitProjected,
    nopat: nopatProjected,
    fcf: fcfProjected,
    pvFactor,
    pv,
  });
}

// ---- TERMINAL VALUE (Gordon Growth Model) ----
// TV = FCF_year10 × (1 + g) / (WACC − g)
const lastFCF = projectedYears[9].fcf;
const terminalFCF = lastFCF * (1 + terminalGrowthRate);
const terminalValue = terminalFCF / (wacc - terminalGrowthRate);
const pvTerminalValue = terminalValue / Math.pow(1 + wacc, 10);

// ---- ENTERPRISE VALUE & EQUITY VALUE ----
const pvFCFs = projectedYears.reduce((sum, y) => sum + y.pv, 0);
const enterpriseValue = pvFCFs + pvTerminalValue;

// Bridge from EV to Equity Value (subtract debt, add cash)
const equityValue = enterpriseValue - fin.totalDebt + fin.cash;
const sharesOutstanding = fin.sharesOutstanding;
const intrinsicValuePerShare = sharesOutstanding > 0 ? equityValue / sharesOutstanding : 0;

if (intrinsicValuePerShare <= 0) {
  throw new Error(`Intrinsic value is negative ($${intrinsicValuePerShare.toFixed(2)}). This may indicate excessive debt or negative FCF. Review inputs.`);
}

// ---- VALUATION VERDICT ----
const currentPrice = fin.currentPrice;
const upside = ((intrinsicValuePerShare - currentPrice) / currentPrice) * 100;
const marginOfSafety = ((intrinsicValuePerShare - currentPrice) / intrinsicValuePerShare) * 100;
const tvAsPctOfEV = (pvTerminalValue / enterpriseValue) * 100;

let recommendation, verdictColor, verdictBg;
if (upside >= 25) {
  recommendation = 'STRONG BUY';
  verdictColor = '#ffffff';
  verdictBg = '#1a7f37';
} else if (upside >= 10) {
  recommendation = 'BUY';
  verdictColor = '#ffffff';
  verdictBg = '#2da44e';
} else if (upside > -10) {
  recommendation = 'HOLD / FAIRLY VALUED';
  verdictColor = '#ffffff';
  verdictBg = '#c6860c';
} else if (upside > -25) {
  recommendation = 'SELL';
  verdictColor = '#ffffff';
  verdictBg = '#cf222e';
} else {
  recommendation = 'STRONG SELL';
  verdictColor = '#ffffff';
  verdictBg = '#82071e';
}

// ---- SENSITIVITY ANALYSIS ----
// 3×3 matrix: WACC (−1%, base, +1%) × TGR (−0.5%, base, +0.5%)
const waccDeltas = [-0.01, 0, 0.01];
const tgrDeltas = [-0.005, 0, 0.005];
const sensitivityMatrix = [];

for (const wd of waccDeltas) {
  const row = [];
  for (const td of tgrDeltas) {
    const w = wacc + wd;
    const g = terminalGrowthRate + td;
    if (w <= g || w <= 0) { row.push(null); continue; }

    // Recalculate PV of FCFs with modified WACC
    let pvFCF_s = 0;
    for (const y of projectedYears) {
      pvFCF_s += y.fcf / Math.pow(1 + w, y.year);
    }
    const tv_s = (lastFCF * (1 + g)) / (w - g);
    const pvTV_s = tv_s / Math.pow(1 + w, 10);
    const ev_s = pvFCF_s + pvTV_s;
    const eq_s = ev_s - fin.totalDebt + fin.cash;
    const ivps = sharesOutstanding > 0 ? eq_s / sharesOutstanding : null;
    row.push(ivps);
  }
  sensitivityMatrix.push(row);
}

return [{
  json: {
    stage1Growth, stage2Growth, terminalGrowthRate,
    reinvestmentRate,
    projectedYears,
    pvFCFs, pvTerminalValue, terminalValue,
    enterpriseValue, equityValue,
    intrinsicValuePerShare, currentPrice,
    upside, marginOfSafety, tvAsPctOfEV,
    recommendation, verdictColor, verdictBg,
    sensitivityMatrix,
    waccVariants: waccDeltas.map(d => wacc + d),
    tgrVariants: tgrDeltas.map(d => terminalGrowthRate + d),
  }
}];

// ============================================================
// STEP 4: GENERATE PROFESSIONAL HTML VALUATION REPORT
// ============================================================

const fin = $('Extract Financial Data').first().json;
const waccData = $('Calculate WACC').first().json;
const dcf = $('DCF Valuation').first().json;

const fmt = (n, dec = 0) => n == null || isNaN(n) ? 'N/A' : n.toLocaleString('en-US', { minimumFractionDigits: dec, maximumFractionDigits: dec });
const fmtPct = (n, dec = 1) => n == null || isNaN(n) ? 'N/A' : (n * 100).toFixed(dec) + '%';
const fmtB = (n) => {
  if (n == null || isNaN(n)) return 'N/A';
  if (Math.abs(n) >= 1e12) return '$' + (n / 1e12).toFixed(2) + 'T';
  if (Math.abs(n) >= 1e9) return '$' + (n / 1e9).toFixed(2) + 'B';
  if (Math.abs(n) >= 1e6) return '$' + (n / 1e6).toFixed(1) + 'M';
  return '$' + fmt(n);
};
const fmtDollar = (n, dec = 2) => n == null || isNaN(n) ? 'N/A' : '$' + n.toFixed(dec);

// Build projected years table rows
const projRows = dcf.projectedYears.map(y => `
  <tr class="${y.year <= 5 ? 'stage1' : 'stage2'}">
    <td>${y.year}</td>
    <td>${fmtPct(y.growthRate)}</td>
    <td>${fmtB(y.revenue)}</td>
    <td>${fmtB(y.ebit)}</td>
    <td>${fmtB(y.nopat)}</td>
    <td>${fmtB(y.fcf)}</td>
    <td>${fmtB(y.pv)}</td>
  </tr>`
).join('');

// Build sensitivity matrix
const sensWaccLabels = dcf.waccVariants.map(w => fmtPct(w));
const sensTGRLabels = dcf.tgrVariants.map(g => fmtPct(g));
const sensRows = dcf.sensitivityMatrix.map((row, wi) => {
  const cells = row.map((val, gi) => {
    if (val === null) return `<td class="sens-na">N/A</td>`;
    const diff = ((val - fin.currentPrice) / fin.currentPrice) * 100;
    const cls = diff >= 15 ? 'sens-buy' : diff <= -15 ? 'sens-sell' : 'sens-hold';
    return `<td class="${cls}">${fmtDollar(val)}<br><small>${diff >= 0 ? '+' : ''}${diff.toFixed(1)}%</small></td>`;
  }).join('');
  return `<tr><td class="sens-label">${sensWaccLabels[wi]}</td>${cells}</tr>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>${fin.ticker} — Intrinsic Valuation Report ${fin.valuationDate}</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Helvetica Neue', Arial, sans-serif; font-size: 11pt; color: #1c1c1e; background: #fff; }
  .page { max-width: 960px; margin: 0 auto; padding: 32px 40px; }
  h1 { font-size: 22pt; font-weight: 700; color: #0a0a0a; }
  h2 { font-size: 13pt; font-weight: 600; color: #1c1c1e; margin: 24px 0 10px; border-bottom: 2px solid #e5e5e5; padding-bottom: 6px; }
  h3 { font-size: 11pt; font-weight: 600; color: #444; margin: 16px 0 8px; }
  .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 24px; }
  .header-left h1 { margin-bottom: 4px; }
  .header-left .subtitle { color: #555; font-size: 10pt; }
  .header-right { text-align: right; font-size: 9pt; color: #777; }
  .verdict-box { border-radius: 10px; padding: 20px 28px; margin: 20px 0; display: flex; align-items: center; gap: 28px; background: ${dcf.verdictBg}; color: ${dcf.verdictColor}; }
  .verdict-label { font-size: 28pt; font-weight: 800; letter-spacing: -1px; }
  .verdict-detail { flex: 1; }
  .verdict-detail .v-row { display: flex; gap: 40px; margin-top: 6px; }
  .verdict-detail .v-item { }
  .verdict-detail .v-item .v-val { font-size: 18pt; font-weight: 700; }
  .verdict-detail .v-item .v-key { font-size: 8pt; opacity: 0.85; text-transform: uppercase; letter-spacing: 0.5px; }
  .metrics-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin: 16px 0; }
  .metric-card { background: #f6f8fa; border-radius: 8px; padding: 12px 14px; }
  .metric-card .mc-label { font-size: 8pt; color: #666; text-transform: uppercase; letter-spacing: 0.4px; margin-bottom: 4px; }
  .metric-card .mc-value { font-size: 14pt; font-weight: 700; color: #1c1c1e; }
  .metric-card .mc-sub { font-size: 8pt; color: #888; margin-top: 2px; }
  table { width: 100%; border-collapse: collapse; font-size: 9.5pt; margin: 8px 0; }
  th { background: #1c1c1e; color: #fff; padding: 7px 10px; text-align: right; font-weight: 600; font-size: 8.5pt; text-transform: uppercase; letter-spacing: 0.3px; }
  th:first-child { text-align: left; }
  td { padding: 6px 10px; text-align: right; border-bottom: 1px solid #ebebeb; }
  td:first-child { text-align: left; }
  tr:hover td { background: #f9f9f9; }
  .stage1 td:first-child { border-left: 3px solid #2da44e; }
  .stage2 td:first-child { border-left: 3px solid #c6860c; }
  .wacc-table th { background: #1a3a5c; }
  .wacc-highlight { background: #e8f0fe !important; font-weight: 700; }
  .sens-buy { background: #d4edda; color: #155724; font-weight: 600; }
  .sens-sell { background: #f8d7da; color: #721c24; font-weight: 600; }
  .sens-hold { background: #fff3cd; color: #856404; }
  .sens-na { background: #f0f0f0; color: #aaa; }
  .sens-label { font-weight: 700; background: #f0f4ff; text-align: center !important; }
  .formula-box { background: #f6f8fa; border-left: 4px solid #1a3a5c; border-radius: 4px; padding: 10px 16px; margin: 8px 0; font-family: 'Courier New', monospace; font-size: 9.5pt; color: #1c1c1e; }
  .step-box { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 14px 18px; margin: 10px 0; }
  .step-num { display: inline-block; background: #1a3a5c; color: #fff; border-radius: 50%; width: 22px; height: 22px; text-align: center; line-height: 22px; font-size: 9pt; font-weight: 700; margin-right: 8px; }
  .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin: 12px 0; }
  .disclaimer { background: #fff8e1; border-left: 4px solid #f9a825; border-radius: 4px; padding: 12px 16px; font-size: 8.5pt; color: #555; margin-top: 24px; }
  .source-link { color: #1a3a5c; text-decoration: none; font-size: 8.5pt; }
  .page-break { page-break-before: always; }
  @media print {
    body { font-size: 10pt; }
    .page { padding: 20px 28px; }
    .verdict-box { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
    .sens-buy, .sens-sell, .sens-hold { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
    th { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  }
</style>
</head>
<body>
<div class="page">

<!-- ===== HEADER ===== -->
<div class="header">
  <div class="header-left">
    <h1>${fin.companyName} (${fin.ticker})</h1>
    <div class="subtitle">${fin.sector} · ${fin.industry} · ${fin.exchange} · ${fin.currency}</div>
    <div class="subtitle" style="margin-top:4px">WACC-Based Intrinsic Valuation</div>
  </div>
  <div class="header-right">
    <div>Valuation Date: <strong>${fin.valuationDate}</strong></div>
    <div style="margin-top:4px">SEC CIK: <a href="${fin.secFilingUrl}" class="source-link">${fin.secCIK}</a></div>
    <div style="margin-top:4px; font-size:8pt; color:#aaa">Methodology: WACC-Based DCF (NYU Stern)</div>
  </div>
</div>

<!-- ===== VERDICT ===== -->
<div class="verdict-box">
  <div class="verdict-label">${dcf.recommendation}</div>
  <div class="verdict-detail">
    <div style="font-size:10pt; opacity:0.9; margin-bottom:8px">DCF Intrinsic Value vs. Current Market Price</div>
    <div class="v-row">
      <div class="v-item"><div class="v-val">${fmtDollar(dcf.intrinsicValuePerShare)}</div><div class="v-key">Intrinsic Value / Share</div></div>
      <div class="v-item"><div class="v-val">${fmtDollar(dcf.currentPrice)}</div><div class="v-key">Current Market Price</div></div>
      <div class="v-item"><div class="v-val">${dcf.upside >= 0 ? '+' : ''}${dcf.upside.toFixed(1)}%</div><div class="v-key">Upside / (Downside)</div></div>
      <div class="v-item"><div class="v-val">${dcf.marginOfSafety.toFixed(1)}%</div><div class="v-key">Margin of Safety</div></div>
    </div>
  </div>
</div>

<!-- ===== KEY METRICS ===== -->
<h2>Key Financial Metrics</h2>
<div class="metrics-grid">
  <div class="metric-card"><div class="mc-label">Market Cap</div><div class="mc-value">${fmtB(fin.marketCap)}</div><div class="mc-sub">Market Value of Equity</div></div>
  <div class="metric-card"><div class="mc-label">Enterprise Value</div><div class="mc-value">${fmtB(fin.enterpriseValueMkt)}</div><div class="mc-sub">Mkt EV (Yahoo Finance)</div></div>
  <div class="metric-card"><div class="mc-label">Revenue (TTM)</div><div class="mc-value">${fmtB(fin.revenue)}</div><div class="mc-sub">Rev. Growth: ${fmtPct(fin.revenueGrowth)}</div></div>
  <div class="metric-card"><div class="mc-label">EBIT (Operating Inc.)</div><div class="mc-value">${fmtB(fin.ebit)}</div><div class="mc-sub">EBIT Margin: ${fmtPct(fin.ebitMargin)}</div></div>
  <div class="metric-card"><div class="mc-label">Free Cash Flow</div><div class="mc-value">${fmtB(fin.fcf)}</div><div class="mc-sub">FCF Margin: ${fmtPct(fin.fcfMargin)}</div></div>
  <div class="metric-card"><div class="mc-label">Total Debt</div><div class="mc-value">${fmtB(fin.totalDebt)}</div><div class="mc-sub">D/E: ${fin.debtToEquity.toFixed(2)}x</div></div>
  <div class="metric-card"><div class="mc-label">Cash & Equivalents</div><div class="mc-value">${fmtB(fin.cash)}</div><div class="mc-sub">Net Debt: ${fmtB(fin.totalDebt - fin.cash)}</div></div>
  <div class="metric-card"><div class="mc-label">ROIC</div><div class="mc-value">${fmtPct(fin.roic)}</div><div class="mc-sub">Return on Invested Capital</div></div>
  <div class="metric-card"><div class="mc-label">Beta (β)</div><div class="mc-value">${fin.beta.toFixed(2)}</div><div class="mc-sub">vs. Market (Yahoo Finance)</div></div>
  <div class="metric-card"><div class="mc-label">Trailing P/E</div><div class="mc-value">${fin.trailingPE ? fin.trailingPE.toFixed(1) + 'x' : 'N/A'}</div><div class="mc-sub">Price / Earnings</div></div>
  <div class="metric-card"><div class="mc-label">Forward P/E</div><div class="mc-value">${fin.forwardPE ? fin.forwardPE.toFixed(1) + 'x' : 'N/A'}</div><div class="mc-sub">Est. Forward Earnings</div></div>
  <div class="metric-card"><div class="mc-label">EV/EBITDA</div><div class="mc-value">${fin.evToEbitda ? fin.evToEbitda.toFixed(1) + 'x' : 'N/A'}</div><div class="mc-sub">Enterprise Multiple</div></div>
</div>

<!-- ===== STEP-BY-STEP METHODOLOGY ===== -->
<h2>Valuation Methodology — Step by Step</h2>

<!-- STEP 1: WACC -->
<div class="step-box">
  <h3><span class="step-num">1</span> Weighted Average Cost of Capital (WACC)</h3>
  <p style="font-size:9.5pt; color:#555; margin:6px 0 10px">The WACC is the discount rate applied to all future cash flows. It reflects the blended required return across equity and debt holders, weighted by market-value capital structure.</p>
  <div class="two-col">
    <div>
      <h3 style="font-size:9.5pt">Cost of Equity — CAPM</h3>
      <div class="formula-box">Re = Rf + β × ERP<br>Re = ${fmtPct(waccData.riskFreeRate)} + ${waccData.beta.toFixed(2)} × ${fmtPct(waccData.ERP)}<br>Re = <strong>${fmtPct(waccData.costOfEquity)}</strong></div>
      <table class="" style="margin-top:8px">
        <tr><td>Risk-Free Rate (Rf)</td><td>${fmtPct(waccData.riskFreeRate)}</td></tr>
        <tr><td>Beta (β)</td><td>${waccData.beta.toFixed(3)}</td></tr>
        <tr><td>Equity Risk Premium (ERP)</td><td>${fmtPct(waccData.ERP)}</td></tr>
        <tr style="font-weight:700"><td>Cost of Equity</td><td>${fmtPct(waccData.costOfEquity)}</td></tr>
      </table>
    </div>
    <div>
      <h3 style="font-size:9.5pt">Cost of Debt (After-tax)</h3>
      <div class="formula-box">Rd = Interest Exp / Total Debt<br>Rd(1−t) = ${fmtPct(waccData.costOfDebtPretax)} × (1 − ${fmtPct(fin.taxRate)})<br>Rd(1−t) = <strong>${fmtPct(waccData.afterTaxCostOfDebt)}</strong></div>
      <table style="margin-top:8px">
        <tr><td>Interest Expense</td><td>${fmtB(fin.interestExpense)}</td></tr>
        <tr><td>Total Debt</td><td>${fmtB(fin.totalDebt)}</td></tr>
        <tr><td>Pre-tax Cost of Debt</td><td>${fmtPct(waccData.costOfDebtPretax)}</td></tr>
        <tr><td>Effective Tax Rate</td><td>${fmtPct(fin.taxRate)}</td></tr>
        <tr style="font-weight:700"><td>After-tax Cost of Debt</td><td>${fmtPct(waccData.afterTaxCostOfDebt)}</td></tr>
      </table>
    </div>
  </div>
  <h3 style="font-size:9.5pt; margin-top:14px">WACC Calculation</h3>
  <div class="formula-box">WACC = We × Re + Wd × Rd(1−t)<br>WACC = ${fmtPct(waccData.weightEquity)} × ${fmtPct(waccData.costOfEquity)} + ${fmtPct(waccData.weightDebt)} × ${fmtPct(waccData.afterTaxCostOfDebt)}<br>WACC = <strong>${fmtPct(waccData.wacc)}</strong></div>
  <table class="wacc-table" style="margin-top:8px">
    <thead><tr><th>Component</th><th>Weight</th><th>Cost</th><th>Weighted Cost</th></tr></thead>
    <tbody>
      <tr><td>Equity (Market Cap)</td><td>${fmtPct(waccData.weightEquity)}</td><td>${fmtPct(waccData.costOfEquity)}</td><td>${fmtPct(waccData.waccComponents.equityContribution)}</td></tr>
      <tr><td>Debt (Total Debt)</td><td>${fmtPct(waccData.weightDebt)}</td><td>${fmtPct(waccData.afterTaxCostOfDebt)}</td><td>${fmtPct(waccData.waccComponents.debtContribution)}</td></tr>
      <tr class="wacc-highlight"><td><strong>WACC</strong></td><td>100%</td><td>—</td><td><strong>${fmtPct(waccData.wacc)}</strong></td></tr>
    </tbody>
  </table>
</div>

<!-- STEP 2: FCF PROJECTIONS -->
<div class="step-box page-break" style="margin-top:20px">
  <h3><span class="step-num">2</span> 10-Year Free Cash Flow Projections</h3>
  <p style="font-size:9.5pt; color:#555; margin:6px 0 10px">FCF is projected using NOPAT × (1 − Reinvestment Rate) with two growth stages. <span style="color:#2da44e; font-weight:600">■ Green = Stage 1 (Yrs 1-5, ${fmtPct(dcf.stage1Growth)} growth)</span> · <span style="color:#c6860c; font-weight:600">■ Orange = Stage 2 (Yrs 6-10, ${fmtPct(dcf.stage2Growth)} growth)</span></p>
  <table>
    <thead><tr><th>Year</th><th>Growth Rate</th><th>Revenue</th><th>EBIT</th><th>NOPAT</th><th>FCFF</th><th>PV of FCFF</th></tr></thead>
    <tbody>
      ${projRows}
      <tr style="font-weight:700; background:#f0f4ff"><td colspan="6">PV of FCFs (Years 1–10)</td><td>${fmtB(dcf.pvFCFs)}</td></tr>
    </tbody>
  </table>

  <h3 style="margin-top:16px">Terminal Value (Gordon Growth Model)</h3>
  <div class="formula-box">TV = FCF₁₀ × (1 + g) / (WACC − g)<br>TV = ${fmtB(dcf.projectedYears[9].fcf)} × (1 + ${fmtPct(dcf.terminalGrowthRate)}) / (${fmtPct(waccData.wacc)} − ${fmtPct(dcf.terminalGrowthRate)})<br>TV = ${fmtB(dcf.terminalValue)} → PV = <strong>${fmtB(dcf.pvTerminalValue)}</strong></div>
  <p style="font-size:8.5pt; color:#888; margin-top:6px">Terminal Value represents ${dcf.tvAsPctOfEV.toFixed(1)}% of Enterprise Value — values above 80% indicate higher model sensitivity.</p>

  <h3 style="margin-top:16px">Bridge: Enterprise Value → Intrinsic Value Per Share</h3>
  <table>
    <tbody>
      <tr><td>PV of Free Cash Flows (Yrs 1–10)</td><td>${fmtB(dcf.pvFCFs)}</td></tr>
      <tr><td>PV of Terminal Value</td><td>${fmtB(dcf.pvTerminalValue)}</td></tr>
      <tr style="font-weight:700"><td>Enterprise Value (DCF)</td><td>${fmtB(dcf.enterpriseValue)}</td></tr>
      <tr><td>Less: Total Debt</td><td style="color:#cf222e">(${fmtB(fin.totalDebt)})</td></tr>
      <tr><td>Plus: Cash & Equivalents</td><td style="color:#2da44e">+${fmtB(fin.cash)}</td></tr>
      <tr style="font-weight:700; background:#f0f4ff"><td>Equity Value</td><td>${fmtB(dcf.equityValue)}</td></tr>
      <tr><td>Shares Outstanding</td><td>${fmt(fin.sharesOutstanding / 1e6)}M</td></tr>
      <tr style="font-weight:800; font-size:12pt; background:#e8f0fe"><td>Intrinsic Value Per Share</td><td>${fmtDollar(dcf.intrinsicValuePerShare)}</td></tr>
      <tr><td>Current Market Price</td><td>${fmtDollar(dcf.currentPrice)}</td></tr>
      <tr style="font-weight:700; color:${dcf.verdictBg}"><td>Upside / (Downside)</td><td>${dcf.upside >= 0 ? '+' : ''}${dcf.upside.toFixed(1)}%</td></tr>
    </tbody>
  </table>
</div>

<!-- STEP 3: SENSITIVITY ANALYSIS -->
<div class="step-box">
  <h3><span class="step-num">3</span> Sensitivity Analysis — Intrinsic Value Per Share</h3>
  <p style="font-size:9.5pt; color:#555; margin:6px 0 10px">Intrinsic value per share across different WACC (rows) and Terminal Growth Rate (columns) assumptions. Shows valuation robustness. <span style="background:#d4edda; padding:2px 6px; border-radius:3px; font-size:8.5pt">Green = BUY (&gt;15% upside)</span> <span style="background:#fff3cd; padding:2px 6px; border-radius:3px; font-size:8.5pt">Yellow = HOLD</span> <span style="background:#f8d7da; padding:2px 6px; border-radius:3px; font-size:8.5pt">Red = SELL (&gt;15% downside)</span></p>
  <table>
    <thead>
      <tr>
        <th>WACC \ TGR</th>
        ${sensTGRLabels.map(l => `<th>${l}</th>`).join('')}
      </tr>
    </thead>
    <tbody>${sensRows}</tbody>
  </table>
  <p style="font-size:8.5pt; color:#888; margin-top:8px">Current Price: ${fmtDollar(fin.currentPrice)} · Base WACC: ${fmtPct(waccData.wacc)} · Base TGR: ${fmtPct(dcf.terminalGrowthRate)}</p>
</div>

<!-- STEP 4: GROWTH ASSUMPTIONS -->
<div class="step-box">
  <h3><span class="step-num">4</span> Key Assumptions Summary</h3>
  <table>
    <thead><tr><th>Assumption</th><th>Value</th><th>Source / Rationale</th></tr></thead>
    <tbody>
      <tr><td>Risk-Free Rate (Rf)</td><td>${fmtPct(waccData.riskFreeRate)}</td><td>10-Year US Treasury (^TNX, Yahoo Finance, live)</td></tr>
      <tr><td>Equity Risk Premium (ERP)</td><td>${fmtPct(waccData.ERP)}</td><td>Implied ERP (NYU Stern) — Jan 2025 (pages.stern.nyu.edu (NYU Stern))</td></tr>
      <tr><td>Beta (β)</td><td>${waccData.beta.toFixed(3)}</td><td>Yahoo Finance (5-year monthly regression vs. S&P 500)</td></tr>
      <tr><td>WACC</td><td>${fmtPct(waccData.wacc)}</td><td>Calculated above</td></tr>
      <tr><td>Revenue Growth — Stage 1 (Yrs 1–5)</td><td>${fmtPct(dcf.stage1Growth)}</td><td>Based on 2-yr CAGR from SEC/Yahoo filings, capped at 20%</td></tr>
      <tr><td>Revenue Growth — Stage 2 (Yrs 6–10)</td><td>${fmtPct(dcf.stage2Growth)}</td><td>Linear fade from Stage 1 toward Terminal</td></tr>
      <tr><td>Terminal Growth Rate (TGR)</td><td>${fmtPct(dcf.terminalGrowthRate)}</td><td>2.5% — Long-run nominal GDP growth (standard DCF convention)</td></tr>
      <tr><td>EBIT Margin</td><td>${fmtPct(fin.ebitMargin)}</td><td>Most recent annual 10-K (stable margin assumption)</td></tr>
      <tr><td>Effective Tax Rate</td><td>${fmtPct(fin.taxRate)}</td><td>Income Tax Expense / Pre-tax Income (from 10-K)</td></tr>
      <tr><td>Reinvestment Rate</td><td>${fmtPct(dcf.reinvestmentRate)}</td><td>(CapEx − D&A) / NOPAT — Capital intensity proxy</td></tr>
    </tbody>
  </table>
</div>

<!-- DATA SOURCES -->
<h2>Data Sources</h2>
<table>
  <thead><tr><th>Data Point</th><th>Source</th><th>URL</th></tr></thead>
  <tbody>
    <tr><td>Financial Statements (Income, B/S, CF)</td><td>Yahoo Finance quoteSummary API</td><td>query2.finance.yahoo.com</td></tr>
    <tr><td>Current Stock Price, Beta, Market Cap</td><td>Yahoo Finance price module</td><td>query2.finance.yahoo.com</td></tr>
    <tr><td>Risk-Free Rate (10-yr Treasury)</td><td>Yahoo Finance ^TNX</td><td>query1.finance.yahoo.com/v8/finance/chart/%5ETNX</td></tr>
    <tr><td>Equity Risk Premium</td><td>NYU Stern</td><td>pages.stern.nyu.edu (NYU Stern)</td></tr>
    <tr><td>SEC Filings (10-K annual reports)</td><td>SEC EDGAR Full-Text Search</td><td><a href="${fin.secFilingUrl}" class="source-link">${fin.secFilingUrl}</a></td></tr>
  </tbody>
</table>

<!-- DISCLAIMER -->
<div class="disclaimer">
  <strong>⚠ Disclaimer:</strong> This report is generated automatically using publicly available data and is for educational and informational purposes only. It does not constitute financial advice, investment advice, or a recommendation to buy or sell any security. All DCF models are sensitive to assumptions — particularly the terminal growth rate and WACC. Past financial performance is not indicative of future results. Always conduct your own due diligence and consult a licensed financial advisor before making investment decisions. Data sourced from Yahoo Finance and SEC EDGAR; timeliness and accuracy are not guaranteed.
</div>

<div style="text-align:center; margin-top:24px; font-size:8pt; color:#bbb">
  Generated by n8n · WACC Valuation Workflow · ${fin.valuationDate} · Methodology: WACC-Based DCF (NYU Stern School of Business)
</div>

</div>
</body>
</html>`;

return [{ json: { html, ticker: fin.ticker, companyName: fin.companyName } }];

const FMP_API_KEY = 'FMP_API_KEY'; // ← paste your key here
